from flask import Flask, send_from_directory, abort, safe_join
import os

app = Flask(__name__)
UPLOADS_DIR = os.path.abspath('uploads')

def is_safe_path(base_path, path):
    try:
        resolved_path = os.path.realpath(safe_join(base_path, path))
        return resolved_path.startswith(base_path)
    except Exception:
        return False

@app.route('/uploads/<path:filename>')
def serve_static_file(filename):
    if is_safe_path(UPLOADS_DIR, filename):
        try:
            return send_from_directory(UPLOADS_DIR, filename)
        except FileNotFoundError:
            abort(404)
    else:
        abort(403)

if __name__ == '__main__':
    app.run()